import{_ as s,r as l,o as i,a as d,b as a,d as n,w as r,F as o,e as t,c as k}from"./app.56afa649.js";const h={},m=a("h1",{id:"stader-land",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#stader-land","aria-hidden":"true"},"#"),t(" St\xE4der/Land")],-1),c=a("p",null,"V\xE4ldigt kortfattat s\xE5 g\xE5r lands ut p\xE5 att skapa ett omr\xE5de/land och bygga en stad. Staden kommer sedan att kosta pengar att ut\xF6ka samt daglig skatt att ha staden ig\xE5ng.",-1),p=a("p",null,"Spelare kan sedan g\xE5 med i staden och hyra tomter att bygga p\xE5 som \xE4garen av staden v\xE4ljer ut. P\xE5 s\xE5 s\xE4tt rullar ekonomin, spelaren betalar skatt till staden och staden betalar skatt till servern.",-1),u=a("p",null,"Att skapa ett nytt land / stad kostar 4000 mynt och man f\xE5r d\xE5 tillg\xE5ng till en s\xE5 kallad chunk. En chunk \xE4r ett omr\xE5de p\xE5 16x16 block fr\xE5n l\xE4gsta punkt till h\xF6gsta.",-1),g=t("Till en b\xF6rjan kan man k\xF6pa ett f\xE5tal omr\xE5den men n\xE4r man \xF6kar i "),b=t("rank"),_=t(" s\xE5 f\xE5r man tillg\xE5ng till fler. Man f\xE5r ocks\xE5 tillg\xE5ng till att bjuda in fler spelare n\xE4r man kl\xE4ttrar i "),f=t("rank"),v=t("."),y=k('<h2 id="skatter" tabindex="-1"><a class="header-anchor" href="#skatter" aria-hidden="true">#</a> Skatter</h2><p>Varje land betalar skatt till servern, kostnaden ligger p\xE5 50 mynt per claimad chunk. Varje inv\xE5nare i landet betalar skatt till landet + eventuell hyra av tomt, denna skatten best\xE4mmer \xE4garen men max \xE4r 1000 mynt om dagen.</p><h3 id="bankrutt" tabindex="-1"><a class="header-anchor" href="#bankrutt" aria-hidden="true">#</a> Bankrutt</h3><p>Om ett land inte kan betala sin skatt s\xE5 kommer servern att ta bort s\xE5 m\xE5nga chunks staden inte kan betala f\xF6r. Tex om varje chunk kostar 50 mynt och landet har claimat 100 chunks s\xE5 kostar detta 500 om dagen. Om landet bara har 450 mynt i sin bank s\xE5 kommer en chunk att bli vildmark, staden f\xF6rlorar allts\xE5 en chunk.</p><p>Om en spelare inte kan betala sin skatt till staden s\xE5 kickas hen och f\xF6rlorar sin eventuella tomt.</p><h3 id="lista-pa-kostnader" tabindex="-1"><a class="header-anchor" href="#lista-pa-kostnader" aria-hidden="true">#</a> Lista p\xE5 kostnader</h3><ul><li>Skapa stad: 4000 mynt.</li><li>Claima en chunk: 1500 mynt.</li><li>Skatt till servern: 50 mynt per chunk.</li><li>Byta namn p\xE5 en stad: 1000 mynt.</li><li>\xC4ndra stadens spawnposition: 400 mynt.</li><li>Byta \xE4gare p\xE5 en stad: 10 000 mynt.</li></ul><h2 id="inaktivitet" tabindex="-1"><a class="header-anchor" href="#inaktivitet" aria-hidden="true">#</a> Inaktivitet</h2><p>Om \xE4garen av ett land / en stad \xE4r inaktiv i 90 dagar s\xE5 flagga den som inaktiv. Det inneb\xE4r att servern kommer f\xF6rs\xF6ka att tills\xE4tta den med n\xE4st h\xF6gst rank i staden som ny \xE4gare och om det inte finns n\xE5gon kommer landet att tas bort.</p><p>Om en inv\xE5nare \xE4r inaktiv i 90 dagar s\xE5 kommer hen att tas bort fr\xE5n staden och spelarens statistik nollst\xE4lls.</p><h2 id="snabbfakta" tabindex="-1"><a class="header-anchor" href="#snabbfakta" aria-hidden="true">#</a> Snabbfakta</h2><ul><li>Man kan ha max 14 bokst\xE4ver i ett stadsnamn.</li><li>Teleporteringstider via st\xE4dernas olika teleportsystem \xE4r tre sekunder.</li><li>Det m\xE5ste vara minst 50 chunks mellan tv\xE5 l\xE4nder.</li><li>En spelare m\xE5ste vara trusted/inv\xE5nare i en stad f\xF6r att s\xE4tta ett hem d\xE4r (/sethome).</li><li>Man kan inte s\xE4lja en tomt, bara hyra.</li><li>Monster och djur som spawnar i wild kan alltid g\xE5 in i en stad.</li><li>En ny stad \xE4r skattebefriad i tv\xE5 dagar.</li></ul>',12);function x(j,S){const e=l("RouterLink");return i(),d(o,null,[m,c,p,u,a("p",null,[g,n(e,{to:"/lands/ranker.html"},{default:r(()=>[b]),_:1}),_,n(e,{to:"/lands/ranker.html"},{default:r(()=>[f]),_:1}),v]),y],64)}var B=s(h,[["render",x],["__file","st\xE4der.html.vue"]]);export{B as default};
